                    elem_j.nb.push(i);
                }
            }
        }
    }

    /// Parallel version. Uses a separate neighbor list with Mutex.
    pub fn build_lists_parallel(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;
        let elems = &self.elems; // immutable access only

        let neighbors: Vec<Mutex<Vec<usize>>> = (0..n)
            .map(|_| Mutex::new(Vec::new()))
            .collect();

        (0..n).into_par_iter().for_each(|i| {
            for j in (i + 1)..n {
                if elems[i].criterion(&elems[j]) < cutoff {
                    neighbors[i].lock().unwrap().push(j);
                    neighbors[j].lock().unwrap().push(i);
                }
            }
        });

        // move results into elems
        for (i, e) in self.elems.iter_mut().enumerate() {
            e.nb = neighbors[i].lock().unwrap().clone();
        }
    }
}

fn main() {
    let mut a = A {
        elems: vec![
            B { r: vec![0.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![1.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![2.0, 0.0, 0.0], ..Default::default() },
            B { r: vec![0.1, 0.1, 0.0], ..Default::default() },
        ],
        cutoff: 1.2,
    };

    a.build_lists();
    println!("single threaded: {:#?}", a);

    a.build_lists_parallel();
    println!("parallel: {:#?}", a);
}
"}

