use std::io::{Read, Write};
use std::os::unix::io::{AsRawFd, FromRawFd};
use std::thread;

fn main() -> std::io::Result<()> {
    // Spawn an interactive shell in a PTY
    let mut session = spawn("/bin/bash").expect("spawn bash in PTY");

    // Duplicate the PTY master FD so we can read and write concurrently
    let master_fd = session.as_raw_fd();
    let write_fd = unsafe { libc::dup(master_fd) };
    assert!(write_fd >= 0, "dup failed");
    let mut writer = unsafe { std::fs::File::from_raw_fd(write_fd) };

