impl ShmBuffer {
    fn new(size: usize) -> ShmBuffer {
        let name = format!("/kitty-shm-{}", std::process::id());
        let cname = CString::new(name.clone()).unwrap();

        let fd = unsafe { shm_open(cname.as_ptr(), O_CREAT | O_RDWR, S_IRUSR | S_IWUSR) };
