        }

        ShmBuffer {
            name,
            ptr: ptr as *mut u8,
            size,
            fd,
        }
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { slice::from_raw_parts_mut(self.ptr, self.size) }
    }
}

