fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // LanceDB returns strings without timezone, sometimes with fractional seconds
    let s = s.trim_matches('"');

    // If there is no fractional part, add ".0" so the %.f parser works
    let s = if s.contains('.') { s.to_string() } else { format!("{}.0", s) };

