{"Cargo.toml":"[package]
name = "manual_poll_tokio"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
futures = "0.3"
","main.rs":"use futures::task::noop_waker;
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use tokio::time::{sleep, Duration};

enum TryPollResult<T> {
    Ready(T),
    Pending,
}

fn try_poll<F: Future>(mut fut: Pin<&mut F>) -> TryPollResult<F::Output> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Non-async function, but can be called from an async context.
fn handle_future<F>(fut: F)
where
    F: Future<Output = String> + Send + 'static,
{
    // Pin it so we can poll safely and still move it afterward.
    let mut fut = Box::pin(fut);

    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(v) => {
            println!("ready: {v}");
        }
        TryPollResult::Pending => {
            // Move the pinned future into a task to await it later.
            tokio::spawn(async move {
                let v = fut.await;
                println!("spawned: {v}");
            });
        }
    }
}

#[tokio::main]
async fn main() {
    // This one completes immediately.
    handle_future(async { "immediate".to_string() });

    // This one will be pending the first poll.
    handle_future(async {
        sleep(Duration::from_millis(100)).await;
        "delayed".to_string()
    });

    // Give the spawned task time to run.
    sleep(Duration::from_millis(200)).await;
}
"}

