","main.rs":"use std::time::Duration;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument};

#[derive(Clone)]
struct RequestCtx {
    // This is the span you create at the start of a request and
    // keep in your context to re‑attach later.
    parent_span: tracing::Span,
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    tracing_subscriber::fmt()
        .with_thread_ids(true)
        .with_span_events(tracing_subscriber::fmt::format::FmtSpan::NEW | tracing_subscriber::fmt::format::FmtSpan::CLOSE)
        .init();

    // The top-level request span
    let request_span = info_span!("request", id = 1);
    let ctx = RequestCtx {
        parent_span: request_span.clone(),
    };

    // Run the request lifecycle under the request span
    let request_fut = async move {
        let s1 = tokio::spawn(stage1(ctx.clone()));
        let s2 = tokio::spawn(stage2(ctx));
        s1.await.unwrap();
        s2.await.unwrap();
    }
    .instrument(request_span);

    request_fut.await;
}

async fn stage1(ctx: RequestCtx) {
    // Rehydrate the parent span by explicitly setting it as parent
    let span = info_span!(parent: &ctx.parent_span, "stage1");
    async move {
        info!("doing stage1");
        sleep(Duration::from_millis(50)).await;
    }
    .instrument(span)
    .await;
}

async fn stage2(ctx: RequestCtx) {
    let span = info_span!(parent: &ctx.parent_span, "stage2");
    async move {
        info!("doing stage2");
        upstream().await;
    }
    .instrument(span)
    .await;
}

async fn upstream() {
    // This becomes a child of the current span (stage2), because
    // stage2 was instrumented and is currently active.
    let span = info_span!("upstream");
    async move {
        info!("calling upstream");
        sleep(Duration::from_millis(30)).await;
    }
    .instrument(span)
    .await;
}
"}

