type ModalResult<T> = Result<T, ContextError>;

#[derive(Debug)]
struct SymbolInterner;

#[derive(Debug)]
struct FilenameInterner;

#[derive(Debug, Clone, Copy)]
struct Filename<'e>(&'e str);

impl FilenameInterner {
    fn new() -> Self {
        Self
    }
    fn intern<'e>(&'e self, name: &str) -> Filename<'e> {
        Filename(name)
    }
}

#[derive(Debug)]
struct State<'e> {
    filename: Filename<'e>,
    symbol_interner: &'e SymbolInterner,
}

#[derive(Debug)]
struct LocatingSlice<'i> {
    input: &'i str,
}

impl<'i> LocatingSlice<'i> {
    fn new(input: &'i str) -> Self {
        Self { input }
    }
}

#[derive(Debug)]
struct Stateful<I, S> {
    input: I,
    state: S,
}

// The primary stream type

type SStream<'i, 'e> = Stateful<LocatingSlice<'i>, State<'e>>;

// ----- a tiny parser trait -----

trait ModalParser<I, O, E> {
    fn parse(&mut self, input: &mut I) -> Result<O, E>;
}

impl<I, O, E, F> ModalParser<I, O, E> for F
where
    F: FnMut(&mut I) -> Result<O, E>,
{
    fn parse(&mut self, input: &mut I) -> Result<O, E> {
        (self)(input)
    }
}

// ----- example output type -----

#[derive(Debug)]
struct Cons<'e> {
    a: u32,
    b: u32,
    _p: PhantomData<&'e ()>,
}

fn cons<'e>(a: u32, b: u32) -> Cons<'e> {
    Cons {
        a,
        b,
        _p: PhantomData,
    }
}

// allow comparing Cons with different lifetimes
impl<'a, 'b> PartialEq<Cons<'b>> for Cons<'a> {
    fn eq(&self, other: &Cons<'b>) -> bool {
        self.a == other.a && self.b == other.b
    }
}

// a parser that produces Cons<'e>
fn parse_cons<'e>(_input: &mut SStream<'_, 'e>) -> ModalResult<Cons<'e>> {
    Ok(cons(1, 2))
}

// ----- The key: a trait with a GAT to carry a lifetime‑dependent output -----

trait OutputType {
    type Out<'e>;
}

struct ConsOut;
impl OutputType for ConsOut {
    type Out<'e> = Cons<'e>;
}

// ----- Generic testing helper -----

pub fn test_input_output<'i, ExOut, POut, P>(
    input: &'i str,
    expected_output: &ExOut,
    mut parser: P,
) where
    POut: OutputType,
    for<'e> P: ModalParser<SStream<'i, 'e>, POut::Out<'e>, ContextError>,
    for<'e> POut::Out<'e>: PartialEq<ExOut> + Debug,
    ExOut: Debug,
{
    let symbol_interner = SymbolInterner;

    let filename_interner = FilenameInterner::new();
    let filename = filename_interner.intern("<test>");

    let mut stateful = SStream {
        input: LocatingSlice::new(input),
        state: State {
            filename,
            symbol_interner: &symbol_interner,
        },
    };

    let parsed = match parser.parse(&mut stateful) {
        Ok(parsed) => parsed,
        Err(_) => {
            panic!(
                "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}"
            )
        }
    };

    println!("Testing input: {input:?}, expected: {expected_output:?}");
    assert_eq!(&parsed, expected_output);
}

fn main() {
    // expected output can have any lifetime; compare works via PartialEq impl
    let expected_output: Cons<'static> = cons(1, 2);

    // POut cannot be inferred from the arguments, so we specify it explicitly.
    test_input_output::<_, ConsOut, _>("(1 . 2)", &expected_output, parse_cons);

    println!("Test succeeded!");
}
"}

