","main.rs":"use tokio::sync::OnceCell;
use tokio::task::JoinHandle;
use tokio_postgres::{Client, NoTls};

// Holds both the Client and the background connection task.
// Keeping the JoinHandle in the struct makes it explicit that the
// connection task is kept alive for as long as the cached client lives.
struct CachedConn {
    client: Client,
    _task: JoinHandle<()>,
}

pub struct DbContainer {
    conn_str: String,
    admin: OnceCell<CachedConn>,
}

impl DbContainer {
    pub fn new(conn_str: impl Into<String>) -> Self {
        Self {
            conn_str: conn_str.into(),
            admin: OnceCell::const_new(),
        }
    }

    // Returns a clone of the cached client. Clones are cheap and keep the
    // underlying connection alive. This avoids borrowing issues and allows
    // concurrent use.
    pub async fn admin_client(&self) -> Result<Client, tokio_postgres::Error> {
        let cached = self
            .admin
            .get_or_try_init(|| async {
                let (client, connection) = tokio_postgres::connect(&self.conn_str, NoTls).await?;
                let task = tokio::spawn(async move {
                    if let Err(e) = connection.await {
                        eprintln!("Connection error: {e}");
                    }
                });
                Ok(CachedConn {
                    client,
                    _task: task,
                })
            })
            .await?;

        Ok(cached.client.clone())
    }
}

