","main.rs":"use bevy::app::ScheduleRunnerPlugin;
use bevy::asset::io::{AssetReader, AssetReaderError, AssetSource, Reader};
use bevy::asset::{AssetApp, AssetLoader, AssetServer, LoadContext, LoadState};
use bevy::prelude::*;
use bevy::utils::BoxedFuture;
use futures_lite::io::Cursor;
use futures_lite::AsyncReadExt;
use std::collections::HashMap;
use std::fs::File;
use std::io::{Read, Seek, SeekFrom, Write};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Duration;

fn main() {
    // Create a small archive so the example is self-contained.
    create_sample_archive();

    App::new()
        .add_plugins(MinimalPlugins)
        .add_plugins(AssetPlugin::default())
        .add_plugins(ScheduleRunnerPlugin::run_loop(Duration::from_millis(50)))
        .add_asset::<MyText>()
        .init_asset_loader::<MyTextLoader>()
        .add_startup_system(setup)
        .add_system(check_loaded)
        .run();
