#[derive(Resource)]
struct LoadedHandle(Handle<MyText>);

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Register a custom asset source that reads from our fake archive.
    let archive_path = PathBuf::from("assets/archive.wad");
    let reader = WadReader::new(archive_path);

    asset_server.register_source(
        "wad",
        AssetSource::build().with_reader(move || Box::new(reader.clone())),
    );

    // Load a text file from the archive lazily.
    let handle: Handle<MyText> = asset_server.load("wad://hello.txt");
    commands.insert_resource(LoadedHandle(handle));
}

fn check_loaded(
    asset_server: Res<AssetServer>,
    texts: Res<Assets<MyText>>,
    handle: Res<LoadedHandle>,
    mut exit: EventWriter<AppExit>,
) {
    if asset_server.load_state(handle.0.id()) == LoadState::Loaded {
        if let Some(text) = texts.get(&handle.0) {
            println!("Loaded text from archive: {}", text.0);
            exit.send(AppExit);
        }
    }
}

// -----------------------------------------------------------------------------
// A very small custom archive format
// -----------------------------------------------------------------------------
// Layout:
// [u32 count]
// For each entry:
//   [u32 name_len][name_bytes]
//   [u32 data_len][data_bytes]

fn create_sample_archive() {
    let _ = std::fs::create_dir_all("assets");
    let mut file = File::create("assets/archive.wad").unwrap();
    let entries = vec![
        ("hello.txt", "Hello from inside the archive!"),
        ("other.txt", "This is another file."),
    ];

    file.write_all(&(entries.len() as u32).to_le_bytes()).unwrap();
    for (name, contents) in entries {
        let name_bytes = name.as_bytes();
        file.write_all(&(name_bytes.len() as u32).to_le_bytes())
            .unwrap();
        file.write_all(name_bytes).unwrap();

        let data_bytes = contents.as_bytes();
        file.write_all(&(data_bytes.len() as u32).to_le_bytes())
            .unwrap();
        file.write_all(data_bytes).unwrap();
    }
}

// -----------------------------------------------------------------------------
// Custom AssetReader that lazily reads from the archive
// -----------------------------------------------------------------------------

#[derive(Clone)]
struct WadReader {
    archive: PathBuf,
    index: Arc<HashMap<PathBuf, Entry>>,
}

#[derive(Clone)]
struct Entry {
    offset: u64,
    length: u64,
}

impl WadReader {
    fn new(archive: PathBuf) -> Self {
        let mut file = File::open(&archive).expect("archive file not found");
        let count = read_u32(&mut file) as usize;
        let mut index = HashMap::new();

        for _ in 0..count {
            let name_len = read_u32(&mut file) as usize;
            let mut name_bytes = vec![0; name_len];
            file.read_exact(&mut name_bytes).unwrap();
            let name = String::from_utf8(name_bytes).unwrap();

            let data_len = read_u32(&mut file) as u64;
            let data_offset = file.seek(SeekFrom::Current(0)).unwrap();
            index.insert(
                PathBuf::from(name),
                Entry {
                    offset: data_offset,
                    length: data_len,
                },
            );
            file.seek(SeekFrom::Current(data_len as i64)).unwrap();
        }

        Self {
            archive,
            index: Arc::new(index),
        }
    }
}

fn read_u32(file: &mut File) -> u32 {
    let mut buf = [0; 4];
    file.read_exact(&mut buf).unwrap();
    u32::from_le_bytes(buf)
}

impl AssetReader for WadReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Reader, AssetReaderError>> {
        Box::pin(async move {
            let entry = self
                .index
                .get(path)
                .ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

            let mut file = File::open(&self.archive).map_err(AssetReaderError::Io)?;
            file.seek(SeekFrom::Start(entry.offset))
                .map_err(AssetReaderError::Io)?;
            let mut buf = vec![0u8; entry.length as usize];
