","main.rs":"use ra_ap_syntax::{ast, ted, AstNode, SyntaxNode};

#[derive(Clone, Debug)]
enum ImportKind {
    Plain,
    Glob,
    Rename(String),
}

#[derive(Clone, Debug)]
struct Import {
    segments: Vec<String>,
    kind: ImportKind,
}

#[derive(Debug, Default)]
struct Node {
    children: Vec<(String, Node)>,
    leaf: Option<ImportKind>,
}

impl Node {
    fn new() -> Self {
        Self {
            children: Vec::new(),
            leaf: None,
        }
    }
}

fn main() {
    let source = r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};

fn main() {}
"#;

    let parse = ast::SourceFile::parse(source);
    let root: SyntaxNode = parse.tree().syntax().clone_for_update();

    rewrite_imports(&root);

    println!("{}", root.to_string());
}

// Rewrite all `use` items in a file.
fn rewrite_imports(root: &SyntaxNode) {
    let use_items: Vec<ast::Use> = root.descendants().filter_map(ast::Use::cast).collect();

    for use_item in use_items {
        if let Some(tree) = use_item.use_tree() {
            // 1) Expand the use tree to a flat list of full paths
            let mut imports = Vec::new();
            collect_imports(&tree, Vec::new(), &mut imports);

            // 2) Rewrite paths in the flat list
            let rewritten: Vec<Import> = imports.into_iter().map(rewrite_import).collect();

            // 3) Build a new use tree from the rewritten list
            let trie = build_trie(&rewritten);
            let new_tree_str = emit_use_tree(&trie);
            let new_tree = use_tree_from_str(&new_tree_str);

            // 4) Replace the old use tree
            ted::replace(tree.syntax(), new_tree.syntax());
        }
    }
}

// Collect all leaf imports from a UseTree.
fn collect_imports(tree: &ast::UseTree, mut prefix: Vec<String>, out: &mut Vec<Import>) {
    if let Some(path) = tree.path() {
        prefix.extend(split_path(&path));
    }

    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            collect_imports(&child, prefix.clone(), out);
        }
        return;
    }

    if tree.star_token().is_some() {
        out.push(Import {
            segments: prefix,
            kind: ImportKind::Glob,
        });
        return;
    }

    if let Some(rename) = tree.rename() {
        let name = rename.name().map(|n| n.to_string()).unwrap_or_default();
        out.push(Import {
            segments: prefix,
            kind: ImportKind::Rename(name),
        });
        return;
    }

    out.push(Import {
        segments: prefix,
        kind: ImportKind::Plain,
    });
}

// Rewrite a single import path: remove `devices` right after `vexide`.
fn rewrite_import(mut imp: Import) -> Import {
    if imp.segments.len() >= 2
        && imp.segments[0] == "vexide"
        && imp.segments[1] == "devices"
    {
        imp.segments.remove(1);
    }
    imp
}

// Split a path into segments (e.g., "vexide::devices" -> ["vexide","devices"]).
fn split_path(path: &ast::Path) -> Vec<String> {
    path.to_string()
        .split("::")
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string())
        .collect()
}

// Build a trie from the list of imports.
fn build_trie(imports: &[Import]) -> Node {
    let mut root = Node::new();
    for imp in imports {
        insert(&mut root, &imp.segments, imp.kind.clone());
    }
    root
}

fn insert(node: &mut Node, path: &[String], kind: ImportKind) {
    if path.is_empty() {
        node.leaf = Some(kind);
        return;
    }

    let name = &path[0];
    if let Some(idx) = node.children.iter().position(|(n, _)| n == name) {
        insert(&mut node.children[idx].1, &path[1..], kind);
    } else {
        let mut new_node = Node::new();
        insert(&mut new_node, &path[1..], kind);
        node.children.push((name.clone(), new_node));
    }
}

// Emit a new use-tree string from the trie.
fn emit_use_tree(root: &Node) -> String {
    let mut items = Vec::new();
    for (name, node) in &root.children {
        items.push(emit_node(name, node));
    }

    if items.len() == 1 {
        items[0].clone()
    } else {
        format!("{{{}}}", items.join(", "))
    }
}

fn emit_node(name: &str, node: &Node) -> String {
    let has_children = !node.children.is_empty();
    match (&node.leaf, has_children) {
        (Some(kind), false) => emit_leaf(name, kind),
        (None, true) => {
            let inner = emit_children(node);
            format!("{name}::{{{inner}}}")
        }
        (Some(kind), true) => {
            let mut items = Vec::new();
            match kind {
                ImportKind::Plain => items.push("self".to_string()),
                ImportKind::Glob => items.push("*".to_string()),
                ImportKind::Rename(r) => items.push(format!("self as {r}")),
            }
            for (child_name, child_node) in &node.children {
                items.push(emit_node(child_name, child_node));
            }
            let inner = items.join(", ");
            format!("{name}::{{{inner}}}")
        }
        (None, false) => name.to_string(),
    }
}

fn emit_children(node: &Node) -> String {
    node.children
        .iter()
        .map(|(name, node)| emit_node(name, node))
        .collect::<Vec<_>>()
        .join(", ")
}

fn emit_leaf(name: &str, kind: &ImportKind) -> String {
    match kind {
        ImportKind::Plain => name.to_string(),
        ImportKind::Glob => format!("{name}::*"),
        ImportKind::Rename(r) => format!("{name} as {r}"),
    }
}

// Parse a use tree from a string like "vexide::{smart, adi}".
fn use_tree_from_str(s: &str) -> ast::UseTree {
    let parse = ast::SourceFile::parse(&format!("use {} ;", s));
    let file = parse.tree();
    let use_item = file
        .syntax()
        .descendants()
        .find_map(ast::Use::cast)
        .unwrap();
    use_item.use_tree().unwrap()
}
"}
